diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2a1218a683ca..bb14b2f55ad8 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1940,6 +1940,24 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,
   if (Value *X = simplifyOrOfICmpsWithAdd(Op1, Op0, Q.IIQ))
     return X;

+  // (icmp ult (add X, Y), X) | (icmp ult (add X, Y), Y) --> icmp ult (add X, Y), X
+  // For unsigned addition, overflow occurs when (X + Y) < X or equivalently
+  // (X + Y) < Y. Therefore both conditions are equivalent and the OR can be
+  // simplified to either one.
+  if (Op0->getPredicate() == ICmpInst::ICMP_ULT &&
+      Op0->getPredicate() == Op1->getPredicate()) {
+    Value *Op0LHS = Op0->getOperand(0), *Op0RHS = Op0->getOperand(1);
+    Value *Op1LHS = Op1->getOperand(0), *Op1RHS = Op1->getOperand(1);
+    if (Op0LHS == Op1LHS) {
+      Value *AddOp0, *AddOp1;
+      if (match(Op0LHS, m_c_Add(m_Value(AddOp0), m_Value(AddOp1)))) {
+        if ((Op0RHS == AddOp0 && Op1RHS == AddOp1) ||
+            (Op0RHS == AddOp1 && Op1RHS == AddOp0))
+          return Op0;
+      }
+    }
+  }
+
   return nullptr;
 }

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..c1733f490389 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3093,6 +3093,20 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     }
   }

+  // (icmp ult (add X, Y), X) | (icmp ult (add X, Y), Y) --> icmp ult (add X, Y), X
+  // For unsigned addition, overflow occurs when (X + Y) < X or equivalently
+  // (X + Y) < Y. Therefore both conditions are equivalent and the OR can be
+  // simplified to either one.
+  if (!IsAnd && PredL == ICmpInst::ICMP_ULT && PredL == PredR &&
+      LHS0 == RHS0) {
+    Value *AddOp0, *AddOp1;
+    if (match(LHS0, m_c_Add(m_Value(AddOp0), m_Value(AddOp1)))) {
+      if ((LHS1 == AddOp0 && RHS1 == AddOp1) ||
+          (LHS1 == AddOp1 && RHS1 == AddOp0))
+        return LHS;
+    }
+  }
+
   // handle (roughly):
